const input = $json || {};
const commandType = String(input.commandType || '').trim().toLowerCase();
const commandText = String(input.commandText || '').trim();

const resultByType = {
  release_sprint: 'Release sprint hiện mới là route demo thôi nha. Tạm thời mình giữ focus vào check sprint để flow chính chạy ổn trước đã.',
  approve: 'Lệnh approve hiện mới là khung demo thôi nha, chưa có pending action thật nào được gắn vào flow chính lúc này.',
  reject: 'Lệnh reject hiện mới là khung demo thôi nha, nên thread này chưa có action thật để từ chối đâu.',
  cancel: 'Lệnh cancel hiện mới là khung demo thôi nha, nên thread này chưa có action thật để huỷ đâu.',
};

const normalizedCommandType = Object.prototype.hasOwnProperty.call(resultByType, commandType)
  ? commandType
  : 'help';

const resultText = normalizedCommandType === 'help'
  ? 'Hiện mình hỗ trợ ổn nhất các lệnh: check sprint, status sprint. Các nhánh demo đang dựng khung để ráp sau: release sprint, approve, reject, cancel.'
  : resultByType[normalizedCommandType];

return {
  toolName: 'assistantDemoCommand',
  toolType: 'read',
  approvalRequired: false,
  executeMode: 'direct',
  resultText,
  resultData: {
    commandType: normalizedCommandType,
    originalCommandText: commandText,
    mode: 'demo',
  },
  proposedAction: null,
  followUpHints: ['check sprint', 'status sprint'],
};
